{
  // The unique identifier name for the gateway
  "name": "Bank",

  // Fixed fee applied to every transaction (e.g., 2.50 EGP)
  "commissionFixed": 2.50,

  // Percentage fee applied to every transaction (e.g., 1.5%)
  "commissionPercentage": 1.5,

  // Maximum total amount that can be processed per day
  "dailyLimit": 500000.00,

  // Minimum allowed per single transaction
  "minTransaction": 10.00,

  // Maximum allowed per single transaction (optional, can be null or removed)
  "maxTransaction": 10000.00,

  // Hours it takes for the transaction to fully settle
  "processingTimeInHours": 24.0,

  // Set to false to enforce the availabilityWindows below
  "available247": false,

  // Optional flag (defaults to true if omitted)
  "active": true,

  // Defines when the gateway is awake and accepting traffic
  "availabilityWindows": [
    {
      "dayOfWeek": "SUNDAY",
      "startTime": "08:00:00",
      "endTime": "23:00:00"
    },
    {
      "dayOfWeek": "MONDAY",
      "startTime": "08:00:00",
      "endTime": "23:00:00"
    }
  ]
}

{
  // Must match the existing name unless you intend to rename it
  "name": "Bank",

  // Lowering the fixed commission
  "commissionFixed": 1.00,

  // Keeping the percentage the same
  "commissionPercentage": 1.5,

  // Increasing the daily limit capacity
  "dailyLimit": 1000000.00,

  "minTransaction": 10.00,
  "maxTransaction": 50000.00,

  // Gateway now settles much faster
  "processingTimeInHours": 1.0,

  // Flipping to 24/7 mode
  "available247": true,

  // Because available247 is true, we can wipe out the specific schedules
  "availabilityWindows": [],

  // Keeping the gateway active
  "active": true
}

{
  // Must match the existing name unless you intend to rename it
  "name": "Bank",

  // Lowering the fixed commission
  "commissionFixed": 1.00,

  // Keeping the percentage the same
  "commissionPercentage": 1.5,

  // Increasing the daily limit capacity
  "dailyLimit": 1000000.00,

  "minTransaction": 10.00,
  "maxTransaction": 50000.00,

  // Gateway now settles much faster
  "processingTimeInHours": 1.0,

  // Flipping to 24/7 mode
  "available247": true,

  // Because available247 is true, we can wipe out the specific schedules
  "availabilityWindows": [],

  // Keeping the gateway active
  "active": true
}

{
  // The name of the organization or biller (Must not be blank)
  "name": "Tony"
}

{
  // The name of the organization or biller (Must not be blank)
  "name": "Global Tech Services",

  // The maximum total transaction amount this biller can process per day across ALL gateways
  // Must be 0 or greater (e.g., 50000.00 EGP)
  "dailyQuota": 50000.00
}

{
  // Updating the name of the biller
  "name": "Global Tech Services LLC",

  // Increasing their daily transaction quota limit
  "dailyQuota": 100000.00
}

{
  // Updating the name of the biller
  "name": "Global Tech Services LLC",

  // Increasing their daily transaction quota limit
  "dailyQuota": 100000.00
}
